framework_css:
/*
  Framework CSS for International Logistics & Shipping Website
  Visual style based on modern corporate hero design with orange + deep blue brand colors.
*/

:root {
  /* Brand colors */
  --color-primary: #FF7A00; /* Bright orange from top bar & primary CTA */
  --color-primary-contrast: #FFFFFF;
  --color-secondary-dark: #00244E; /* Deep blue for footer & headings */
  --color-secondary: #007ACC; /* Accent blue */

  /* Neutral palette */
  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F5F5F5;
  --color-neutral-200: #DDDDDD;
  --color-neutral-400: #888888;
  --color-neutral-900: #222222;

  /* Semantic */
  --color-success: #28A745;
  --color-error: #DC3545;
  --color-warning: #FFC107;
  --color-info: #17A2B8;

  /* Typography */
  --font-heading: "Space Grotesk", "Helvetica", sans-serif;
  --font-body: "Source Sans 3", "Arial", sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-base: 16px;
  --font-size-h1: 3rem; /* 48px */
  --font-size-h2: 2rem; /* 32px */
  --font-size-h3: 1.5rem; /* 24px */
  --font-size-small: 0.8125rem; /* 13px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --spacing-1: 4px;
  --spacing-2: 8px;
  --spacing-3: 16px;
  --spacing-4: 24px;
  --spacing-5: 32px;
  --spacing-6: 48px;
  --spacing-7: 64px;

  /* Layout */
  --header-height-topbar: 40px;
  --header-height-main: 80px;
  --content-max-width: 1200px;

  /* Shadows */
  --shadow-soft: 0 2px 4px rgba(0, 0, 0, 0.03);
  --shadow-card: 0 4px 12px rgba(0, 0, 0, 0.06);
}

/* Global reset & base styles */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: var(--font-size-base);
  scroll-behavior: smooth;
}

body {
  margin: 0;
  font-family: var(--font-body);
  color: var(--color-neutral-900);
  background-color: var(--color-neutral-000);
  line-height: var(--line-height-normal);
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  color: var(--color-primary);
}

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  color: var(--color-secondary-dark);
  margin: 0 0 var(--spacing-3);
}

h1 { font-size: var(--font-size-h1); line-height: var(--line-height-tight); }
 h2 { font-size: var(--font-size-h2); line-height: var(--line-height-tight); }
 h3 { font-size: var(--font-size-h3); line-height: var(--line-height-tight); }

p {
  margin: 0 0 var(--spacing-3);
}

code,
pre {
  font-family: var(--font-code);
}

.container {
  width: 100%;
  max-width: var(--content-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--spacing-4);
  padding-right: var(--spacing-4);
}

.layout-default {
  background-color: var(--color-neutral-000);
}

/* Header */

.site-header {
  position: relative;
  z-index: 1000;
  box-shadow: var(--shadow-soft);
}

/* Top utility bar */

.top-bar {
  background-color: var(--color-primary);
  color: var(--color-primary-contrast);
  font-size: var(--font-size-small);
}

.top-bar-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height-topbar);
}

.top-bar-left,
.top-bar-right {
  display: flex;
  align-items: center;
}

.top-bar-item {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
}

/* Simple circular glyphs to echo phone/email icons in the design */

.top-bar-phone::before,
.top-bar-email::before {
  content: "";
  width: 16px;
  height: 16px;
  border-radius: 50%;
  border: 2px solid var(--color-primary-contrast);
  opacity: 0.9;
}

/* Main navigation bar */

.main-header {
  background-color: var(--color-neutral-000);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height-main);
}

/* Brand / logo approximation */

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
}

.brand-mark {
  width: 44px;
  height: 44px;
  border-radius: 50%;
  background: linear-gradient(135deg, #FFB347, var(--color-primary));
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.brand-mark-inner {
  display: block;
  width: 60%;
  height: 60%;
  border-radius: 50%;
  border: 3px solid var(--color-primary-contrast);
  border-top-color: transparent;
  border-left-color: transparent;
  transform: rotate(35deg);
}

.brand-text {
  display: flex;
  flex-direction: column;
}

.brand-name {
  font-family: var(--font-heading);
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  font-size: 0.95rem;
  color: var(--color-secondary-dark);
}

/* Primary nav links */

.primary-nav {
  margin-left: auto;
  margin-right: var(--spacing-4);
}

.nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  align-items: center;
  gap: var(--spacing-4);
}

.nav-item {
  position: relative;
}

.nav-link {
  font-family: var(--font-heading);
  font-weight: 500;
  font-size: 0.9375rem; /* 15px */
  padding: var(--spacing-3) 0;
  color: var(--color-neutral-900);
  position: relative;
}

.nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  background-color: var(--color-primary);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 0.18s ease-out;
}

.nav-link:hover::after,
.nav-link:focus::after,
.nav-link.active::after {
  transform: scaleX(1);
}

.nav-link:hover,
.nav-link:focus {
  color: var(--color-secondary-dark);
}

/* Visual search icon (non-interactive) */

.nav-search {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.nav-search-icon {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: 2px solid var(--color-neutral-900);
  position: relative;
}

.nav-search-icon::after {
  content: "";
  position: absolute;
  width: 9px;
  height: 2px;
  background-color: var(--color-neutral-900);
  border-radius: 999px;
  transform: rotate(45deg);
  right: -4px;
  bottom: -1px;
}

/* Main content area */

.site-content {
  min-height: 50vh;
  background-color: var(--color-neutral-000);
  padding-top: var(--spacing-6);
  padding-bottom: var(--spacing-6);
}

/* Footer */

.site-footer {
  margin-top: auto;
}

.footer-main {
  background-color: var(--color-secondary-dark);
  color: var(--color-neutral-000);
  padding-top: var(--spacing-6);
  padding-bottom: var(--spacing-6);
  border-top: 4px solid var(--color-primary);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-5);
}

.footer-column {
  flex: 1 1 220px;
}

.footer-logo {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  margin-bottom: var(--spacing-3);
}

.footer-description {
  margin: 0;
  max-width: 320px;
  font-size: 0.875rem;
  line-height: var(--line-height-relaxed);
  color: rgba(255, 255, 255, 0.82);
}

.footer-heading {
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 1rem;
  margin: 0 0 var(--spacing-3);
  color: var(--color-neutral-000);
}

.footer-link-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.footer-link-list a {
  font-size: 0.875rem;
  color: rgba(255, 255, 255, 0.8);
}

.footer-link-list a:hover,
.footer-link-list a:focus {
  color: var(--color-primary-contrast);
  text-decoration: underline;
}

.footer-bottom {
  background-color: #001835; /* Slightly darker than main footer */
  color: rgba(255, 255, 255, 0.7);
  font-size: 0.75rem;
}

.footer-bottom-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--spacing-3);
  padding-bottom: var(--spacing-3);
}

.footer-copy {
  margin: 0;
}

/* Buttons (for future use in hero/other sections) */

.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem 1.75rem;
  background-color: var(--color-primary);
  color: var(--color-primary-contrast);
  border-radius: 4px;
  font-family: var(--font-heading);
  font-weight: 600;
  font-size: 0.9375rem;
  border: none;
  text-decoration: none;
  box-shadow: 0 6px 10px rgba(0, 0, 0, 0.18);
  transition: background-color 0.16s ease-out, transform 0.16s ease-out, box-shadow 0.16s ease-out;
  cursor: pointer;
}

.btn-primary:hover,
.btn-primary:focus {
  background-color: #e66c00;
  transform: translateY(-1px);
  box-shadow: 0 8px 18px rgba(0, 0, 0, 0.22);
}

.btn-primary:active {
  transform: translateY(0);
  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.18);
}

/* Card pattern (for future content sections) */

.card {
  background-color: var(--color-neutral-000);
  border-radius: 4px;
  box-shadow: var(--shadow-card);
  padding: var(--spacing-4);
}

.card-title {
  font-family: var(--font-heading);
  font-weight: 600;
  margin-bottom: var(--spacing-2);
}

.card-text {
  font-size: 0.9375rem;
  color: var(--color-neutral-900);
}

/* Form pattern (for future use) */

.form-group {
  margin-bottom: var(--spacing-3);
}

.form-label {
  display: block;
  margin-bottom: var(--spacing-1);
  font-size: 0.875rem;
  font-weight: 500;
}

.form-control {
  width: 100%;
  padding: 0.625rem 0.875rem;
  border-radius: 4px;
  border: 1px solid var(--color-neutral-200);
  font-family: var(--font-body);
  font-size: 0.9375rem;
}

.form-control:focus {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 2px rgba(255, 122, 0, 0.15);
}

.form-control.error {
  border-color: var(--color-error);
}

.form-helper-text {
  margin-top: 4px;
  font-size: 0.75rem;
  color: var(--color-neutral-400);
}

.form-helper-text.error {
  color: var(--color-error);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    height: auto;
    padding-top: var(--spacing-2);
    padding-bottom: var(--spacing-2);
  }

  .brand {
    margin-bottom: var(--spacing-2);
  }

  .primary-nav {
    order: 3;
    width: 100%;
    margin: 0;
  }

  .nav-list {
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--spacing-3);
  }

  .nav-link {
    padding: var(--spacing-2) 0;
  }
}

@media (max-width: 600px) {
  .top-bar-inner {
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    height: auto;
    padding-top: 4px;
    padding-bottom: 4px;
    gap: 2px;
  }

  .footer-inner {
    flex-direction: column;
  }

  .footer-bottom-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--spacing-2);
  }
}
